import{_ as o,o as t,c as r,ak as s}from"./chunks/framework.tZEZYUNo.js";const h=JSON.parse('{"title":"CI/CD and workflow behavior","description":"","frontmatter":{},"headers":[],"relativePath":"ci-cd.md","filePath":"ci-cd.md"}'),a={name:"ci-cd.md"};function n(i,e,l,c,d,g){return t(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="ci-cd-and-workflow-behavior" tabindex="-1">CI/CD and workflow behavior <a class="header-anchor" href="#ci-cd-and-workflow-behavior" aria-label="Permalink to “CI/CD and workflow behavior”">​</a></h1><p>All workflows live under <a href="https://github.com/bcgov/bcew-monorepo/tree/main/.github/workflows" target="_blank" rel="noreferrer"><code>.github/workflows/</code></a>. This page summarizes behavior; inline workflow comments and the <a href="https://github.com/bcgov/bcew-monorepo/blob/main/.github/workflows/README.md" target="_blank" rel="noreferrer">workflows README</a> are authoritative for details.</p><h2 id="pull-requests-pr-yml" tabindex="-1">Pull requests (<code>pr.yml</code>) <a class="header-anchor" href="#pull-requests-pr-yml" aria-label="Permalink to “Pull requests (pr.yml)”">​</a></h2><p><strong>Triggers:</strong> Every <code>pull_request</code> event.</p><p><strong>Concurrency:</strong> One run per PR; newer commits cancel in-progress runs for that PR.</p><p><strong>Typical steps:</strong></p><ol><li><strong>Labeler</strong> — Applies labels from <code>.github/labeler.yml</code> based on changed paths.</li><li><strong>Install</strong> — pnpm and Node (see workflow for versions), <code>pnpm install</code>, root <code>composer install</code>.</li><li><strong>Lint</strong> — Full monorepo lint: PHP, JS, CSS, Markdown, <code>package.json</code>.</li><li><strong>Build</strong> — <code>npx nx affected --base=&quot;origin/&lt;base_branch&gt;&quot; -t build</code> so only <strong>affected</strong> projects build.</li><li><strong>Tests</strong>: <ol><li><strong>Integration</strong> — PHP WordPress integration tests using wp-env.</li><li><strong>e2e</strong> — e2e tests using Playwright and wp-env.</li><li><strong>Screenshot</strong> — Visual regression tests using Playwright and wp-env. Compares screenshots <ul><li><strong>Note</strong>: If a screenshot test fails in the CI/CD, check the artifact it uploads during the <code>actions/upload-artifact</code> step. It will contain a zip of the diff between the expected screenshots and the ones it produced. Usually the fix for this will require running <code>npx nx test-screenshot-generate</code> locally to generate new screenshots.</li></ul></li></ol></li><li><strong>Artifacts</strong> — Playwright report uploaded on completion (unless cancelled).</li></ol><h3 id="how-affected-is-chosen" tabindex="-1">How “affected” is chosen <a class="header-anchor" href="#how-affected-is-chosen" aria-label="Permalink to “How “affected” is chosen”">​</a></h3><p>The PR workflow compares the PR head to <code>origin/&lt;github.base_ref&gt;</code> (the target branch, usually <code>main</code>). Any project touched or implied by the Nx graph runs the expensive targets.</p><p>Reusable workflow <code>detect-affected-projects.yml</code> exists for <strong>callable</strong> workflows; it computes affected <strong>app</strong> projects for a given base/head. Keep it in mind if you add new workflows that need the same logic.</p><h2 id="merges-to-main" tabindex="-1">Merges to <code>main</code> <a class="header-anchor" href="#merges-to-main" aria-label="Permalink to “Merges to main”">​</a></h2><ul><li><strong>Docs:</strong> Pushes to <code>main</code> that touch <code>docs/**</code>, package <code>docs/**</code>, sync script, or docs workflow deploy the VitePress site via <code>deploy-docs.yml</code> (see <a href="./documentation-site">Documentation site</a>).</li><li><strong>Releases:</strong> Merging code does <strong>not</strong> by itself publish plugin/theme zip artifacts. Publishing is <strong>tag-driven</strong> (<code>tag.yml</code>).</li></ul><h2 id="tags-tag-yml" tabindex="-1">Tags (<code>tag.yml</code>) <a class="header-anchor" href="#tags-tag-yml" aria-label="Permalink to “Tags (tag.yml)”">​</a></h2><p><strong>Triggers:</strong> Push of tags matching <code>**/v*</code> (for example <code>bcew-blocks/v1.2.0</code>).</p><p><strong>Behavior (high level):</strong></p><ol><li>Checkout with full history.</li><li>Parse tag into <strong>project name</strong> (Nx project) and <strong>version</strong>.</li><li><code>nx run &lt;project&gt;:composer-install</code> and <code>nx run &lt;project&gt;:build</code>.</li><li>Create <code>dist.zip</code> from the project directory using <code>git archive</code> (respects <code>.gitattributes</code> export rules), copy in <code>dist/</code> build output, and for <code>X.Y.Z</code> tags update the WordPress version header only inside the zip.</li><li>Create a <strong>GitHub Release</strong> with <code>dist.zip</code> attached.</li><li>Update <strong><code>packages.json</code></strong> for the Composer repository hosted on GitHub Pages and deploy the <code>public/</code> output.</li></ol><p>See <a href="./release-and-deployment">Release and deployment</a> for the consumer-facing model.</p><h2 id="permissions" tabindex="-1">Permissions <a class="header-anchor" href="#permissions" aria-label="Permalink to “Permissions”">​</a></h2><p>Workflows use least privilege where possible; <code>tag.yml</code> and docs deploy require <code>contents: write</code> (and Pages-related permissions) for releases and <code>gh-pages</code> updates.</p>',19)])])}const u=o(a,[["render",n]]);export{h as __pageData,u as default};
